void SetTextMode()

{

   if(textMode==0)

   {

      Sound_Holder.StopAll();



      DisableScreen();

      Sprite_Holder.ChangePhase(0,status[0]);

      Sprite_Holder.ChangePhase(1,status[1]);

      Sprite_Holder.ChangePhase(2,status[2]);

      Sprite_Holder.ChangePhase(3,status[3]);

      Sprite_Holder.ChangePhase(4,status[4]);

      Sprite_Holder.ChangePhase(5,status[5]);

      Sprite_Holder.ChangePhase(6,status[6]);

      Sprite_Holder.ChangePhase(7,status[7]);

      Sprite_Holder.ChangePhase(8,status[8]);

      Sprite_Holder.ChangePhase(9,status[9]);

      Sprite_Holder.ChangePhase(10,status[10]);

      Sprite_Holder.ChangePhase(11,status[11]);



      Sprite_Holder.HideSprite(12);

      Sprite_Holder.HideSprite(13);



      Sprite_Holder.MoveTo(18,-100,250);

      Sprite_Holder.ShowSprite(18);



      switch(tryb)

      {

         case 0:

            Sprite_Holder.ShowSprite(12);

            Sprite_Holder.ShowSprite(13);

            break;

         case 1:

            Sprite_Holder.ShowSprite(14);

            break;

         case 2:

            Sprite_Holder.ShowSprite(15);

            break;

         case 3:

            Sprite_Holder.ShowSprite(16);

            break;

         case 4:

            Sprite_Holder.ShowSprite(17);

            break;

         case 5:

            Sprite_Holder.MoveTo(18,-100,250);

            Sprite_Holder.GotoXY(18,700,250);

            Sprite_Holder.ShowSprite(18);

            break;

      }

      Sprite_Holder.SynchronizeTimers();



      playStatus = 0;

      Sound_Holder.Stop(8);

      Text_Holder.HideText(0);

      Text_Holder.StopSynchroText(0);



      Sound_Holder.PlayDSound(biezacaMuzyka);

      Sound_Holder.SetPlayDSoundParameters( biezacaMuzyka, 0, 0, 0 );



      SetCursor(1);



      EnableScreen();

      ShowBuffer();

   }

   else

   {

      Sound_Holder.StopAll();



      DisableScreen();

      Sprite_Holder.ChangePhase(0,0);

      Sprite_Holder.ChangePhase(1,1);

      Sprite_Holder.ChangePhase(2,3);

      Sprite_Holder.ChangePhase(3,4);

      Sprite_Holder.ChangePhase(4,2);

      Sprite_Holder.ChangePhase(5,5);

      Sprite_Holder.ChangePhase(6,5);

      Sprite_Holder.ChangePhase(7,4);

      Sprite_Holder.ChangePhase(8,2);

      Sprite_Holder.ChangePhase(9,1);

      Sprite_Holder.ChangePhase(10,3);

      Sprite_Holder.ChangePhase(11,0);



      Sprite_Holder.HideSprite(14);

      Sprite_Holder.HideSprite(15);

      Sprite_Holder.HideSprite(16);

      Sprite_Holder.HideSprite(17);

      Sprite_Holder.HideSprite(18);



      Sprite_Holder.ShowSprite(12);

      Sprite_Holder.ShowSprite(13);



      playStatus = 1;   

      Sound_Holder.PlayDSound(0);

      Sound_Holder.SetPlayDSoundParameters(0, -1000, 0, 0 );

      Sound_Holder.PlayDSound(8);

      Text_Holder.SetTextOffsets(0,0,0);

      Text_Holder.DisableMouse(0);

      Text_Holder.ShowText(0);

      SetCursor(0);



      EnableScreen();

      ShowBuffer();

   }

}







